      sendBinary: this.sendBinary.bind(this),
      logger: sdkLogger,
      getPackageName: () => this.config.packageName,
      getSessionId: () => this.runtimeSessionId,
      getServerUrl: () => this.getServerUrl(),
      permissions: this.permissions
