// src/utils/bitmap-utils.ts
import * as fs from "fs/promises";
import * as path from "path";
import { Jimp } from "jimp";

class BitmapUtils {
  static async convert24BitTo1BitBMP(input24BitBmp) {
    const width = input24BitBmp.readUInt32LE(18);
    const height = Math.abs(input24BitBmp.readInt32LE(22));
    const isTopDown = input24BitBmp.readInt32LE(22) < 0;
    const bitsPerPixel = input24BitBmp.readUInt16LE(28);
    if (bitsPerPixel !== 24) {
      throw new Error("Input must be a 24-bit BMP");
    }
    const rowSize24 = Math.ceil(width * 3 / 4) * 4;
    const rowSize1 = Math.ceil(width / 32) * 4;
    const colorTableSize = 8;
    const headerSize = 54 + colorTableSize;
    const pixelDataSize = rowSize1 * height;
    const fileSize = headerSize + pixelDataSize;
    const output1BitBmp = Buffer.alloc(fileSize);
    let offset = 0;
    output1BitBmp.write("BM", offset);
    offset += 2;
    output1BitBmp.writeUInt32LE(fileSize, offset);
    offset += 4;
    output1BitBmp.writeUInt16LE(0, offset);
    offset += 2;
    output1BitBmp.writeUInt16LE(0, offset);
    offset += 2;
    output1BitBmp.writeUInt32LE(headerSize, offset);
    offset += 4;
    output1BitBmp.writeUInt32LE(40, offset);
    offset += 4;
    output1BitBmp.writeInt32LE(width, offset);
    offset += 4;
    output1BitBmp.writeInt32LE(height, offset);
    offset += 4;
    output1BitBmp.writeUInt16LE(1, offset);
    offset += 2;
    output1BitBmp.writeUInt16LE(1, offset);
    offset += 2;
    output1BitBmp.writeUInt32LE(0, offset);
    offset += 4;
    output1BitBmp.writeUInt32LE(pixelDataSize, offset);
    offset += 4;
    output1BitBmp.writeInt32LE(2835, offset);
    offset += 4;
    output1BitBmp.writeInt32LE(2835, offset);
    offset += 4;
    output1BitBmp.writeUInt32LE(2, offset);
    offset += 4;
    output1BitBmp.writeUInt32LE(2, offset);
    offset += 4;
    output1BitBmp.writeUInt32LE(0, offset);
    offset += 4;
    output1BitBmp.writeUInt8(255, offset++);
    output1BitBmp.writeUInt8(255, offset++);
    output1BitBmp.writeUInt8(255, offset++);
    output1BitBmp.writeUInt8(0, offset++);
    const pixelDataStart24 = 54;
    for (let y = 0;y < height; y++) {
      const sourceY = isTopDown ? y : height - 1 - y;
      const destY = height - 1 - y;
      const rowData = Buffer.alloc(rowSize1);
      for (let x = 0;x < width; x++) {
        const offset24 = pixelDataStart24 + sourceY * rowSize24 + x * 3;
        const blue = input24BitBmp[offset24];
        const green = input24BitBmp[offset24 + 1];
        const red = input24BitBmp[offset24 + 2];
        const isWhite = red > 128 || green > 128 || blue > 128 ? 1 : 0;
        const byteIndex = Math.floor(x / 8);
        const bitPosition = 7 - x % 8;
        if (isWhite) {
          rowData[byteIndex] |= 1 << bitPosition;
        }
      }
      const destOffset = offset + destY * rowSize1;
      rowData.copy(output1BitBmp, destOffset);
    }
    return output1BitBmp;
  }
  static async fileToBase64(filePath) {
    try {
      const bmpData = await fs.readFile(filePath);
      return this.bufferToBase64(bmpData);
    } catch (error) {
      if (error instanceof Error) {
        throw new Error(`Failed to load BMP file ${filePath}: ${error.message}`);
      }
      throw new Error(`Failed to load BMP file ${filePath}: Unknown error`);
    }
  }
  static async bufferToBase64(bmpData) {
    return bmpData.toString("base64");
  }
  static async padBase64Bitmap(bmpBase64, padding) {
    const buffer = Buffer.from(bmpBase64, "base64");
    const paddedBuffer = await this.padBmpForGlasses(buffer, padding?.left, padding?.top);
    return paddedBuffer.toString("base64");
  }
  static async padBmpForGlasses(bmpData, leftPadding = 50, topPadding = 35) {
    try {
      if (bmpData.length < 14 || bmpData[0] !== 66 || bmpData[1] !== 77) {
        throw new Error(`Bmp data is not a valid BMP file (missing BM signature)`);
      }
      let finalBmpData = bmpData;
      const image = await Jimp.read(bmpData);
      if (image.width !== 576 || image.height !== 135) {
        console.log(`Adding padding to BMP since it isn't 576x135 (assuming it's 526x100!)(current: ${image.width}x${image.height})`);
        const paddedImage = new Jimp({
          width: 576,
          height: 135,
          color: 0
        });
        const leftPadding2 = 50;
        const topPadding2 = 35;
        paddedImage.composite(image, leftPadding2, topPadding2);
        finalBmpData = await this.convert24BitTo1BitBMP(await paddedImage.getBuffer("image/bmp"));
      }
      console.log(`finalBmpData: ${finalBmpData.length} bytes`);
      return finalBmpData;
    } catch (error) {
      if (error instanceof Error) {
        throw new Error(`Failed to load BMP data: ${error.message}`);
      }
      throw new Error(`Failed to load BMP data: Unknown error`);
    }
  }
  static async loadBmpFrames(basePath, frameCount, options = {}) {
    const {
      filePattern = "animation_10_frame_{i}.bmp",
      startFrame = 1,
      validateFrames = true,
      skipMissingFrames = false
    } = options;
    const frames = [];
    const errors = [];
    for (let i = 0;i < frameCount; i++) {
      const frameNumber = startFrame + i;
      const fileName = filePattern.replace("{i}", frameNumber.toString());
      const filePath = path.join(basePath, fileName);
      try {
        const frameBase64 = await this.fileToBase64(filePath);
        if (validateFrames) {
          const validation = this.validateBase64Bitmap(frameBase64);
          if (!validation.isValid) {
            const errorMsg = `Frame ${frameNumber} validation failed: ${validation.errors.join(", ")}`;
            if (skipMissingFrames) {
              console.warn(`⚠️ ${errorMsg} - skipping`);
              continue;
            } else {
              throw new Error(errorMsg);
            }
          }
          console.log(`✅ Frame ${frameNumber} validated (${validation.blackPixels} black pixels)`);
        }
        frames.push(frameBase64);
      } catch (error) {
        const errorMsg = `Failed to load frame ${frameNumber} (${fileName}): ${error instanceof Error ? error.message : "Unknown error"}`;
        if (skipMissingFrames) {
          console.warn(`⚠️ ${errorMsg} - skipping`);
          continue;
        } else {
          errors.push(errorMsg);
        }
      }
    }
    if (errors.length > 0) {
      throw new Error(`Failed to load frames:
${errors.join(`
`)}`);
    }
    if (frames.length === 0) {
      throw new Error(`No valid frames loaded from ${basePath}`);
    }
    console.log(`\uD83D\uDCDA Loaded ${frames.length} animation frames from ${basePath}`);
    return frames;
  }
  static validateBase64Bitmap(bmpFrame) {
    const errors = [];
    let byteCount = 0;
    let blackPixels = 0;
    const metadata = {};
    try {
      const hexString = Buffer.from(bmpFrame, "base64").toString("hex");
      if (typeof hexString !== "string" || hexString.length === 0) {
        errors.push("Hex string is empty or invalid");
        return { isValid: false, byteCount: 0, blackPixels: 0, errors };
      }
      if (hexString.length % 2 !== 0) {
        errors.push("Hex string length must be even");
        return { isValid: false, byteCount: 0, blackPixels: 0, errors };
      }
      const buffer = Buffer.from(hexString, "hex");
      byteCount = buffer.length;
      if (buffer.length < 14) {
        errors.push("File too small to be a valid BMP (minimum 14 bytes for header)");
      } else {
        if (buffer[0] !== 66 || buffer[1] !== 77) {
          errors.push('Invalid BMP signature (should start with "BM")');
        }
      }
      const expectedSize = 9782;
      if (buffer.length < expectedSize - 100) {
        errors.push(`BMP too small (${buffer.length} bytes, expected ~${expectedSize})`);
      } else if (buffer.length > expectedSize + 1000) {
        errors.push(`BMP too large (${buffer.length} bytes, expected ~${expectedSize})`);
      }
      if (buffer.length >= 54) {
        try {
          const width = buffer.readUInt32LE(18);
          const height = buffer.readUInt32LE(22);
          metadata.dimensions = { width, height };
          metadata.format = "BMP";
          if (width !== 576 || height !== 135) {
            errors.push(`Invalid dimensions (${width}x${height}, expected 576x135 for MentraOS)`);
          }
        } catch (e) {
          errors.push("Failed to parse BMP header metadata");
        }
      }
      if (buffer.length > 62) {
        const pixelData = buffer.slice(62);
        blackPixels = Array.from(pixelData).filter((b) => b !== 255).length;
        if (blackPixels === 0) {
          errors.push("No black pixels found (image appears to be all white)");
        }
      } else {
        errors.push("File too small to contain pixel data");
      }
    } catch (error) {
      errors.push(`Failed to parse hex data: ${error instanceof Error ? error.message : "Unknown error"}`);
    }
    return {
      isValid: errors.length === 0,
      byteCount,
      blackPixels,
      errors,
      metadata: Object.keys(metadata).length > 0 ? metadata : undefined
    };
  }
  static convertFormat(data, fromFormat, toFormat) {
    let buffer;
    switch (fromFormat) {
      case "hex":
        buffer = Buffer.from(data, "hex");
        break;
      case "base64":
        buffer = Buffer.from(data, "base64");
        break;
      case "buffer":
        buffer = data;
        break;
      default:
        throw new Error(`Unsupported source format: ${fromFormat}`);
    }
    switch (toFormat) {
      case "hex":
        return buffer.toString("hex");
      case "base64":
        return buffer.toString("base64");
      case "buffer":
        return buffer;
      default:
        throw new Error(`Unsupported target format: ${toFormat}`);
    }
  }
  static getBitmapInfo(hexString) {
    try {
      const buffer = Buffer.from(hexString, "hex");
      const isValidBmp = buffer.length >= 14 && buffer[0] === 66 && buffer[1] === 77;
      let width;
      let height;
      if (isValidBmp && buffer.length >= 54) {
        try {
          width = buffer.readUInt32LE(18);
          height = buffer.readUInt32LE(22);
        } catch (e) {}
      }
      const pixelData = buffer.slice(62);
      const blackPixels = Array.from(pixelData).filter((b) => b !== 255).length;
      return {
        byteCount: buffer.length,
        blackPixels,
        width,
        height,
        isValidBmp
      };
    } catch (error) {
      return {
        byteCount: 0,
        blackPixels: 0,
        isValidBmp: false
      };
    }
  }
}
// src/utils/animation-utils.ts
class AnimationUtils {
  static delay(ms) {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
  static async createBitmapAnimation(session, basePath, frameCount, config = {}) {
    const {
      intervalMs = 1750,
      repeat = false,
      validateFrames = true,
      loadOptions = {},
      onStart,
      onStop,
      onFrame,
      onError
    } = config;
    try {
      console.log(`\uD83C\uDFAC Loading ${frameCount} animation frames from ${basePath}...`);
      const frames = await BitmapUtils.loadBmpFrames(basePath, frameCount, {
        validateFrames,
        ...loadOptions
      });
      if (frames.length === 0) {
        throw new Error("No frames loaded for animation");
      }
      console.log(`\uD83D\uDCDA Animation ready: ${frames.length} frames at ${intervalMs}ms intervals`);
      return this.createBitmapAnimationFromFrames(session, frames, {
        intervalMs,
        repeat,
        onStart,
        onStop,
        onFrame,
        onError
      });
    } catch (error) {
      const errorMsg = `Failed to create animation: ${error instanceof Error ? error.message : "Unknown error"}`;
      console.error(`❌ ${errorMsg}`);
      if (onError) {
        onError(errorMsg);
      }
      throw new Error(errorMsg);
    }
  }
  static createBitmapAnimationFromFrames(session, frames, config = {}) {
    const {
      intervalMs = 1750,
      repeat = false,
      onStart,
      onStop,
      onFrame,
      onError
    } = config;
    let isRunning = false;
    const currentFrame = 0;
    let animationController = null;
    const controller = {
      stop: () => {
        if (animationController) {
          animationController.stop();
          animationController = null;
        }
        isRunning = false;
        if (onStop) {
          onStop();
        }
        console.log("\uD83D\uDED1 Animation stopped");
      },
      isRunning: () => isRunning,
      getCurrentFrame: () => currentFrame,
      getTotalFrames: () => frames.length
    };
    try {
      animationController = session.layouts.showBitmapAnimation(frames, intervalMs, repeat);
      isRunning = true;
      if (onStart) {
        onStart();
      }
      console.log(`\uD83C\uDFAC Animation started: ${frames.length} frames at ${intervalMs}ms${repeat ? " (repeating)" : ""}`);
      if (onFrame) {
        let frameTracker = 0;
        onFrame(frameTracker, frames.length);
        const frameInterval = setInterval(() => {
          if (!isRunning) {
            clearInterval(frameInterval);
            return;
          }
          frameTracker = (frameTracker + 1) % frames.length;
          onFrame(frameTracker, frames.length);
          if (!repeat && frameTracker === frames.length - 1) {
            clearInterval(frameInterval);
          }
        }, intervalMs);
        const originalStop = controller.stop;
        controller.stop = () => {
          clearInterval(frameInterval);
          originalStop();
        };
      }
    } catch (error) {
      const errorMsg = `Failed to start animation: ${error instanceof Error ? error.message : "Unknown error"}`;
      console.error(`❌ ${errorMsg}`);
      if (onError) {
        onError(errorMsg);
      }
      throw new Error(errorMsg);
    }
    return controller;
  }
  static async createBitmapSequence(session, sequence) {
    console.log(`\uD83C\uDFAD Starting bitmap sequence: ${sequence.length} frames with custom timing`);
    for (let i = 0;i < sequence.length; i++) {
      const { frame, duration } = sequence[i];
      try {
        console.log(`\uD83D\uDCFD️ Sequence frame ${i + 1}/${sequence.length} (${duration}ms)`);
        session.layouts.showBitmapView(frame);
        if (i < sequence.length - 1) {
          await this.delay(duration);
        }
      } catch (error) {
        console.error(`❌ Error in sequence frame ${i + 1}:`, error);
        throw error;
      }
    }
    console.log("✅ Bitmap sequence completed");
  }
  static async measureTiming(targetInterval, measureDuration = 1e4) {
    return new Promise((resolve) => {
      const timestamps = [];
      const startTime = Date.now();
      const measureInterval = setInterval(() => {
        timestamps.push(Date.now());
      }, targetInterval);
      setTimeout(() => {
        clearInterval(measureInterval);
        if (timestamps.length < 2) {
          resolve({
            targetInterval,
            actualInterval: targetInterval,
            drift: 0,
            fps: 1000 / targetInterval
          });
          return;
        }
        const intervals = [];
        for (let i = 1;i < timestamps.length; i++) {
          intervals.push(timestamps[i] - timestamps[i - 1]);
        }
        const actualInterval = intervals.reduce((a, b) => a + b, 0) / intervals.length;
        const drift = actualInterval - targetInterval;
        const fps = 1000 / actualInterval;
        resolve({
          targetInterval,
          actualInterval,
          drift,
          fps
        });
      }, measureDuration);
    });
  }
  static getOptimizedConfig(deviceType) {
    switch (deviceType) {
      case "even-realities-g1":
        return {
          intervalMs: 1650,
          repeat: false,
          validateFrames: true,
          loadOptions: {
            validateFrames: true,
            skipMissingFrames: false
          }
        };
      case "generic":
      default:
        return {
          intervalMs: 1000,
          repeat: false,
          validateFrames: true,
          loadOptions: {
            validateFrames: true,
            skipMissingFrames: false
          }
        };
    }
  }
  static async preloadFrames(basePath, frameCount, options = {}) {
    console.log(`\uD83D\uDCE6 Preloading ${frameCount} frames from ${basePath}...`);
    const frames = await BitmapUtils.loadBmpFrames(basePath, frameCount, {
      validateFrames: true,
      ...options
    });
    console.log(`✅ Preloaded ${frames.length} frames (${frames.reduce((total, frame) => total + frame.length, 0)} total characters)`);
    return frames;
  }
}

