var KNOWN_DIST_TAGS = ["alpha", "beta", "hono", "rc", "canary", "next"];
function getDistTag(version) {
  const pattern = new RegExp(`-(${KNOWN_DIST_TAGS.join("|")})`);
  const match = version.match(pattern);
  return match ? match[1] : "latest";
}

