class LayoutManager {
  packageName;
  sendMessage;
  constructor(packageName, sendMessage) {
    this.packageName = packageName;
    this.sendMessage = sendMessage;
  }
  createDisplayEvent(layout, view = "main" /* MAIN */, durationMs) {
    try {
      if (!layout) {
        throw new Error("Layout cannot be null or undefined");
      }
      if (!layout.layoutType) {
        throw new Error("Layout must have a layoutType property");
      }
      switch (layout.layoutType) {
        case "text_wall" /* TEXT_WALL */:
          if (typeof layout.text !== "string") {
            throw new Error("TextWall layout must have a text property");
          }
          if (layout.text.length > 1000) {
            console.warn("TextWall text is very long, this may cause performance issues");
          }
          break;
        case "double_text_wall" /* DOUBLE_TEXT_WALL */:
          const doubleText = layout;
          if (typeof doubleText.topText !== "string") {
            throw new Error("DoubleTextWall layout must have a topText property");
          }
          if (typeof doubleText.bottomText !== "string") {
            throw new Error("DoubleTextWall layout must have a bottomText property");
          }
          break;
        case "reference_card" /* REFERENCE_CARD */:
          const refCard = layout;
          if (typeof refCard.title !== "string") {
            throw new Error("ReferenceCard layout must have a title property");
          }
          if (typeof refCard.text !== "string") {
            throw new Error("ReferenceCard layout must have a text property");
          }
          break;
        case "dashboard_card" /* DASHBOARD_CARD */:
          const dashCard = layout;
          if (typeof dashCard.leftText !== "string") {
            throw new Error("DashboardCard layout must have a leftText property");
          }
          if (typeof dashCard.rightText !== "string") {
            throw new Error("DashboardCard layout must have a rightText property");
          }
          break;
        case "bitmap_view" /* BITMAP_VIEW */:
          const bitmapView = layout;
          if (typeof bitmapView.data !== "string") {
            throw new Error("BitmapView layout must have a data property");
          }
          if (bitmapView.data.length > 1e6) {
            throw new Error("Bitmap data is too large (>1MB), please reduce size");
          }
          break;
        case "clear_view" /* CLEAR_VIEW */:
          break;
      }
      if (view !== "main" /* MAIN */ && view !== "dashboard" /* DASHBOARD */) {
        console.warn(`Invalid view type: ${view}, defaulting to MAIN`);
        view = "main" /* MAIN */;
      }
      if (durationMs !== undefined) {
        if (typeof durationMs !== "number" || durationMs < 0) {
          console.warn(`Invalid duration: ${durationMs}, ignoring`);
          durationMs = undefined;
        }
      }
      return {
        timestamp: new Date,
        sessionId: "",
        type: "display_event" /* DISPLAY_REQUEST */,
        packageName: this.packageName,
        view,
        layout,
        durationMs
      };
    } catch (error) {
      console.error("Error creating display event:", error);
      throw error;
    }
  }
  showTextWall(text, options) {
    try {
      if (text === undefined || text === null) {
        text = "";
        console.warn("showTextWall called with null/undefined text");
      }
      if (typeof text !== "string") {
        text = String(text);
        console.warn("showTextWall: Non-string input converted to string");
      }
      const layout = {
        layoutType: "text_wall" /* TEXT_WALL */,
        text
      };
      try {
        const displayEvent = this.createDisplayEvent(layout, options?.view, options?.durationMs);
        this.sendMessage(displayEvent);
      } catch (error) {
        console.error("Failed to display text wall:", error);
      }
    } catch (error) {
      console.error("Error in showTextWall:", error);
    }
  }
  showDoubleTextWall(topText, bottomText, options) {
    const layout = {
      layoutType: "double_text_wall" /* DOUBLE_TEXT_WALL */,
      topText,
      bottomText
    };
    this.sendMessage(this.createDisplayEvent(layout, options?.view, options?.durationMs));
  }
  showReferenceCard(title, text, options) {
    const layout = {
      layoutType: "reference_card" /* REFERENCE_CARD */,
      title,
      text
    };
    this.sendMessage(this.createDisplayEvent(layout, options?.view, options?.durationMs));
  }
  async showBitmapView(base64Bitmap, options) {
    const padding = options?.padding ?? { left: 50, top: 35 };
    const bitmapFrame = await BitmapUtils.padBase64Bitmap(base64Bitmap, padding);
    const validation = BitmapUtils.validateBase64Bitmap(bitmapFrame);
    if (!validation.isValid) {
      throw new Error(`❌ Frame validation failed: ${validation.errors.join(", ")}`);
    }
    const layout = {
      layoutType: "bitmap_view" /* BITMAP_VIEW */,
      data: bitmapFrame
    };
    this.sendMessage(this.createDisplayEvent(layout, options?.view));
  }
  showDashboardCard(leftText, rightText, options) {
    const layout = {
      layoutType: "dashboard_card" /* DASHBOARD_CARD */,
      leftText,
      rightText
    };
    this.sendMessage(this.createDisplayEvent(layout, options?.view || "dashboard" /* DASHBOARD */, options?.durationMs));
  }
  clearView(options) {
    const layout = {
      layoutType: "clear_view" /* CLEAR_VIEW */
    };
    this.sendMessage(this.createDisplayEvent(layout, options?.view));
  }
  showBitmapAnimation(bitmapDataArray, intervalMs = 1650, repeat = false, options) {
    if (!Array.isArray(bitmapDataArray) || bitmapDataArray.length === 0) {
      throw new Error("showBitmapAnimation requires a non-empty array of bitmap data");
    }
    const layout = {
      layoutType: "bitmap_animation" /* BITMAP_ANIMATION */,
      frames: bitmapDataArray,
      interval: intervalMs,
      repeat
    };
    this.sendMessage(this.createDisplayEvent(layout, options?.view));
    console.log(`\uD83C\uDFAC Sent batched animation to iOS: ${bitmapDataArray.length} frames at ${intervalMs}ms${repeat ? " (repeating)" : ""}`);
    return {
      stop: () => {
        this.clearView();
        console.log("\uD83D\uDED1 Animation stop requested");
      }
    };
  }
}

// src/app/session/settings.ts
import EventEmitter4 from "events";

// src/app/session/api-client.ts
function wsUrlToHttpUrl(wsUrl) {
  if (!wsUrl)
    return;
  try {
    const url = new URL(wsUrl);
    const protocol = url.protocol === "wss:" ? "https:" : "http:";
    return `${protocol}//${url.host}`;
  } catch (error) {
    console.error("Error converting WebSocket URL to HTTP URL:", error);
    return;
  }
}

class ApiClient {
  baseUrl;
  packageName;
  userId;
  constructor(packageName, wsUrl, userId) {
    this.packageName = packageName;
    this.userId = userId;
    if (wsUrl) {
      this.baseUrl = wsUrlToHttpUrl(wsUrl);
    }
  }
  setWebSocketUrl(wsUrl) {
    this.baseUrl = wsUrlToHttpUrl(wsUrl);
  }
  setUserId(userId) {
    this.userId = userId;
  }
  async fetchSettings() {
    if (!this.baseUrl) {
      throw new Error("API client is not configured with a base URL");
    }
    if (!this.userId) {
      throw new Error("User ID is required for fetching settings");
    }
    const url = `${this.baseUrl}/appsettings/user/${this.packageName}`;
    try {
      const response = await fetch(url, {
        method: "GET",
        headers: {
          Authorization: `Bearer ${this.userId}`,
          "Content-Type": "application/json"
        }
      });
      if (!response.ok) {
        throw new Error(`Failed to fetch settings: ${response.status} ${response.statusText}`);
      }
      const data = await response.json();
      return data.settings || [];
    } catch (error) {
      console.error("Error fetching settings:", error);
      throw error;
    }
  }
}

// src/app/session/settings.ts
class SettingsManager {
  settings = [];
  emitter = new EventEmitter4;
  apiClient;
  logger;
  mentraosSettings = {};
  mentraosEmitter = new EventEmitter4;
  subscribeFn;
  constructor(initialSettings = [], packageName, wsUrl, userId, subscribeFn, logger2) {
    this.settings = [...initialSettings];
    this.subscribeFn = subscribeFn;
    if (logger2) {
      this.logger = logger2.child({ module: "settings" });
    } else {
      const { logger: defaultLogger } = (init_logger(), __toCommonJS(exports_logger));
      this.logger = defaultLogger.child({ module: "settings" });
    }
    if (packageName) {
      this.apiClient = new ApiClient(packageName, wsUrl, userId);
    }
  }
  configureApiClient(packageName, wsUrl, userId) {
    if (!this.apiClient) {
      this.apiClient = new ApiClient(packageName, wsUrl, userId);
    } else {
      this.apiClient.setWebSocketUrl(wsUrl);
      this.apiClient.setUserId(userId);
    }
  }
  updateSettings(newSettings) {
    const changes = {};
    const updatedSettings = [...newSettings];
    for (const newSetting of updatedSettings) {
      const oldSetting = this.settings.find((s) => s.key === newSetting.key);
      if (oldSetting && this.areEqual(oldSetting.value, newSetting.value)) {
        continue;
      }
      changes[newSetting.key] = {
        oldValue: oldSetting?.value,
        newValue: newSetting.value
      };
    }
    for (const oldSetting of this.settings) {
      const stillExists = updatedSettings.some((s) => s.key === oldSetting.key);
      if (!stillExists) {
        changes[oldSetting.key] = {
          oldValue: oldSetting.value,
          newValue: undefined
        };
      }
    }
    if (Object.keys(changes).length > 0) {
      this.settings = updatedSettings;
      this.emitChanges(changes);
    }
    return changes;
  }
  areEqual(a, b) {
    return a === b;
  }
  emitChanges(changes) {
    this.emitter.emit("settings:change" /* CHANGE */, changes);
    for (const [key, change] of Object.entries(changes)) {
      this.emitter.emit(`${"settings:value:" /* VALUE_CHANGE */}${key}`, change.newValue, change.oldValue);
    }
  }
  onChange(handler) {
    this.emitter.on("settings:change" /* CHANGE */, handler);
    return () => this.emitter.off("settings:change" /* CHANGE */, handler);
  }
  onValueChange(key, handler) {
    const eventName = `${"settings:value:" /* VALUE_CHANGE */}${key}`;
    this.emitter.on(eventName, handler);
    return () => this.emitter.off(eventName, handler);
  }
  has(key) {
    return this.settings.some((s) => s.key === key);
  }
  getAll() {
    return [...this.settings];
  }
  get(key, defaultValue) {
    const setting = this.settings.find((s) => s.key === key);
    if (setting && setting.value !== undefined) {
      return setting.value;
    }
    return defaultValue;
  }
  getMentraOS(key, defaultValue) {
    const value = this.mentraosSettings[key];
    if (value !== undefined) {
      return value;
    }
    return defaultValue;
  }
  getSetting(key) {
    return this.settings.find((s) => s.key === key);
  }
  async fetch() {
    if (!this.apiClient) {
      throw new Error("Settings API client is not configured");
    }
    try {
      const newSettings = await this.apiClient.fetchSettings();
      this.updateSettings(newSettings);
      return this.settings;
    } catch (error) {
      this.logger.error({ error }, "Error fetching settings");
      throw error;
    }
  }
  onMentraosChange(key, handler) {
    return this.onMentraosSettingChange(key, handler);
  }
  onMentraosSettingsChange(key, handler) {
    return this.onMentraosSettingChange(key, handler);
  }
  updateMentraosSettings(newSettings) {
    const oldSettings = this.mentraosSettings;
    this.logger.debug({ newSettings }, `[SettingsManager] Updating MentraOS settings. New settings`);
    for (const key of Object.keys(newSettings)) {
      const oldValue = oldSettings[key];
      const newValue = newSettings[key];
      if (oldValue !== newValue) {
        this.logger.debug(`[SettingsManager] MentraOS setting '${key}' changed: ${oldValue} -> ${newValue}. Emitting event.`);
        this.mentraosEmitter.emit(`augmentos:value:${key}`, newValue, oldValue);
      }
    }
    for (const key of Object.keys(oldSettings)) {
      if (!(key in newSettings)) {
        this.logger.debug(`[SettingsManager] MentraOS setting '${key}' removed. Old value: ${oldSettings[key]}. Emitting event with undefined newValue.`);
        this.mentraosEmitter.emit(`augmentos:value:${key}`, undefined, oldSettings[key]);
      }
    }
    this.mentraosSettings = { ...newSettings };
    this.logger.debug({ mentraosSettings: this.mentraosSettings }, `[SettingsManager] Finished updating MentraOS settings. Current state:`);
  }
  onMentraosSettingChange(key, handler) {
    const eventName = `augmentos:value:${key}`;
    this.logger.debug(`[SettingsManager] Registering handler for MentraOS setting '${key}' on event '${eventName}'.`);
    this.mentraosEmitter.on(eventName, (...args) => {
      this.logger.debug({ args }, `[SettingsManager] MentraOS setting '${key}' event fired. Args:`);
      handler(...args);
    });
    if (this.subscribeFn) {
      const subscriptionKey3 = `augmentos:${key}`;
      this.logger.debug(`[SettingsManager] Calling subscribeFn for stream '${subscriptionKey3}'.`);
      this.subscribeFn([subscriptionKey3]).then(() => {
        this.logger.debug(`[SettingsManager] subscribeFn resolved for stream '${subscriptionKey3}'.`);
      }).catch((err) => {
        this.logger.error(`[SettingsManager] subscribeFn failed for stream '${subscriptionKey3}':`, err);
      });
    } else {
      this.logger.warn(`[SettingsManager] 'subscribeFn' not provided. Cannot auto-subscribe for MentraOS setting '${key}'. Manual App subscription might be required.`);
    }
    return () => {
      this.logger.debug(`[SettingsManager] Unregistering handler for MentraOS setting '${key}' from event '${eventName}'.`);
      this.mentraosEmitter.off(eventName, handler);
    };
  }
  getMentraosSetting(key, defaultValue) {
    this.logger.debug({ key, mentraosSettings: this.mentraosSettings }, `Getting MentraOS setting '${key}'`);
    if (key in this.mentraosSettings) {
      return this.mentraosSettings[key];
    }
    return defaultValue;
  }
}

