init_types();
init_streams();

// src/app/session/modules/camera-managed-extension.ts
init_types();

class CameraManagedExtension {
  session;
  packageName;
  sessionId;
  logger;
  isManagedStreaming = false;
  currentManagedStreamId;
  currentManagedStreamUrls;
  managedStreamStatus;
  pendingStreamChecks;
  pendingManagedStreamRequest;
  constructor(session, packageName, sessionId, logger2) {
    this.session = session;
    this.packageName = packageName;
    this.sessionId = sessionId;
    this.logger = logger2.child({ module: "CameraManagedExtension" });
  }
  async startManagedStream(options = {}) {
    this.logger.info({ options }, "Managed stream request starting");
    if (this.isManagedStreaming) {
      this.logger.error({
        currentStreamId: this.currentManagedStreamId
      }, "Already managed streaming error");
      throw new Error("Already streaming. Stop the current managed stream before starting a new one.");
    }
    const request = {
      type: "managed_stream_request" /* MANAGED_STREAM_REQUEST */,
      packageName: this.packageName,
      video: options.video,
      audio: options.audio,
      stream: options.stream,
      restreamDestinations: options.restreamDestinations,
      sound: options.sound
    };
    this.session.sendMessage(request);
    this.isManagedStreaming = true;
    return new Promise((resolve, reject) => {
      this.pendingManagedStreamRequest = { resolve, reject };
      setTimeout(() => {
        if (this.pendingManagedStreamRequest) {
          this.pendingManagedStreamRequest = undefined;
          this.isManagedStreaming = false;
          reject(new Error("Managed stream request timeout"));
        }
      }, 30000);
    });
  }
  async stopManagedStream() {
    this.logger.debug({
      streamId: this.currentManagedStreamId,
      hasInternalState: this.isManagedStreaming
    }, "Sending managed stream stop request");
    const request = {
      type: "managed_stream_stop" /* MANAGED_STREAM_STOP */,
      packageName: this.packageName
    };
    this.session.sendMessage(request);
  }
  async checkExistingStream() {
    return new Promise((resolve) => {
      const requestId = `stream_check_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
      if (!this.pendingStreamChecks) {
        this.pendingStreamChecks = new Map;
      }
      const timeoutId = setTimeout(() => {
        this.pendingStreamChecks?.delete(requestId);
        resolve({ hasActiveStream: false });
      }, 5000);
      this.pendingStreamChecks.set(requestId, {
        resolve,
        timeoutId
      });
      const request = {
        type: "stream_status_check" /* STREAM_STATUS_CHECK */,
        packageName: this.packageName,
        sessionId: this.sessionId
      };
      this.session.sendMessage(request);
    });
  }
  isManagedStreamActive() {
    return this.isManagedStreaming;
  }
  getManagedStreamUrls() {
    return this.currentManagedStreamUrls;
  }
  getManagedStreamStatus() {
    return this.managedStreamStatus;
  }
  onManagedStreamStatus(handler) {
    if (!this.session) {
      this.logger.error("Cannot listen for managed status updates: session reference not available");
      return () => {};
    }
    this.session.subscribe("managed_stream_status" /* MANAGED_STREAM_STATUS */);
    return this.session.on("managed_stream_status" /* MANAGED_STREAM_STATUS */, handler);
  }
  handleStreamCheckResponse(response) {
    if (this.pendingStreamChecks && this.pendingStreamChecks.size > 0) {
      const firstEntry = this.pendingStreamChecks.entries().next();
      if (!firstEntry.done && firstEntry.value) {
        const [requestId, pending] = firstEntry.value;
        if (pending) {
          clearTimeout(pending.timeoutId);
          this.pendingStreamChecks.delete(requestId);
          pending.resolve(response);
        }
      }
    }
  }
  handleManagedStreamStatus(status) {
    this.logger.debug({
      status: status.status,
      streamId: status.streamId
    }, "Received managed stream status");
    this.managedStreamStatus = status;
    if (status.status === "initializing" && status.streamId) {
      this.isManagedStreaming = true;
      this.currentManagedStreamId = status.streamId;
    }
    if (status.status === "active") {
      this.isManagedStreaming = true;
      this.currentManagedStreamId = status.streamId;
      if (status.hlsUrl && status.dashUrl) {
        const result = {
          hlsUrl: status.hlsUrl,
          dashUrl: status.dashUrl,
          webrtcUrl: status.webrtcUrl,
          previewUrl: status.previewUrl,
          thumbnailUrl: status.thumbnailUrl,
          streamId: status.streamId || ""
        };
        this.currentManagedStreamUrls = result;
        if (this.pendingManagedStreamRequest) {
          this.pendingManagedStreamRequest.resolve(result);
          this.pendingManagedStreamRequest = undefined;
        }
      }
    }
    if ((status.status === "error" || status.status === "stopped") && this.pendingManagedStreamRequest) {
      this.pendingManagedStreamRequest.reject(new Error(status.message || "Managed stream failed"));
      this.pendingManagedStreamRequest = undefined;
      this.isManagedStreaming = false;
      this.currentManagedStreamId = undefined;
      this.currentManagedStreamUrls = undefined;
    }
    if (status.status === "stopped") {
      this.isManagedStreaming = false;
      this.currentManagedStreamId = undefined;
      this.currentManagedStreamUrls = undefined;
    }
    if (status.status === "error") {
      this.isManagedStreaming = false;
      this.currentManagedStreamId = undefined;
      this.currentManagedStreamUrls = undefined;
    }
  }
  cleanup() {
    if (this.pendingManagedStreamRequest) {
      this.pendingManagedStreamRequest.reject(new Error("Camera module cleanup"));
      this.pendingManagedStreamRequest = undefined;
    }
    this.isManagedStreaming = false;
    this.currentManagedStreamId = undefined;
    this.currentManagedStreamUrls = undefined;
    this.managedStreamStatus = undefined;
    this.logger.debug("Managed streaming extension cleaned up");
  }
}

// src/app/session/modules/camera.ts
init_permissions_utils();
var VALID_ROI_POSITIONS = ["center", "top", "bottom"];

class CameraModule {
  session;
  packageName;
  sessionId;
  logger;
  isStreaming = false;
  currentStreamUrl;
  currentStreamState;
  managedExtension;
  constructor(session, packageName, sessionId, logger2) {
    this.session = session;
    this.packageName = packageName;
    this.sessionId = sessionId;
    this.logger = logger2 || console;
    this.managedExtension = new CameraManagedExtension(session, packageName, sessionId, this.logger);
  }
  async requestPhoto(options) {
    return new Promise((resolve, reject) => {
      const baseUrl = this.session?.getHttpsServerUrl?.() || "";
      cameraWarnLog(baseUrl, this.packageName, "requestPhoto");
      try {
        const requestId = `photo_req_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
        this.session.appServer.registerPhotoRequest(requestId, {
          userId: this.session.userId,
          sessionId: this.sessionId,
          session: this.session,
          resolve,
          reject: (error) => reject(error.message),
          timestamp: Date.now()
        });
        const message = {
          type: "photo_request" /* PHOTO_REQUEST */,
          packageName: this.packageName,
          sessionId: this.sessionId,
          requestId,
          timestamp: new Date,
          saveToGallery: options?.saveToGallery || false,
          customWebhookUrl: options?.customWebhookUrl,
          authToken: options?.authToken,
          size: options?.size || "medium",
          compress: options?.compress || "none",
          sound: options?.sound
        };
        this.session.sendMessage(message);
        this.logger.info({
          requestId,
          saveToGallery: options?.saveToGallery,
          hasCustomWebhook: !!options?.customWebhookUrl,
          hasAuthToken: !!options?.authToken
        }, `\uD83D\uDCF8 Photo request sent`);
        if (options?.customWebhookUrl) {
          this.logger.info({ requestId, customWebhookUrl: options.customWebhookUrl }, `\uD83D\uDCF8 Using custom webhook URL - resolving promise immediately since photo will be uploaded directly to custom endpoint`);
          const pending = this.session.appServer.completePhotoRequest(requestId);
          if (pending) {
            const mockPhotoData = {
              buffer: Buffer.from([]),
              mimeType: "image/jpeg",
              filename: "photo.jpg",
              requestId,
              size: 0,
              timestamp: new Date
            };
            pending.resolve(mockPhotoData);
          }
          return;
        }
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : String(error);
        reject(`Failed to request photo: ${errorMessage}`);
      }
    });
  }
  hasPhotoPendingRequest(requestId) {
    return this.session.appServer.getPhotoRequest(requestId) !== undefined;
  }
  cancelPhotoRequest(requestId) {
    const pending = this.session.appServer.completePhotoRequest(requestId);
    if (pending) {
      pending.reject(new Error("Photo request cancelled"));
      this.logger.debug({ requestId }, "Photo request cancelled");
      return true;
    }
    return false;
  }
  cancelAllPhotoRequests() {
    this.logger.debug("cancelAllPhotoRequests called — cleanup now happens at AppServer level");
    return 0;
  }
  async setFov(options) {
    const { fov } = options;
    let roiPosition = options.roiPosition ?? "center";
    if (fov < 82 || fov > 118) {
      throw new Error(`fov must be between 82 and 118, got ${fov}`);
    }
    if (!VALID_ROI_POSITIONS.includes(roiPosition)) {
      throw new Error(`roiPosition must be one of ${VALID_ROI_POSITIONS.join(", ")}, got "${roiPosition}"`);
    }
    if (fov === 118) {
      roiPosition = "center";
    }
    const requestId = `cam_fov_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
    const message = {
      type: "camera_fov_set" /* CAMERA_FOV_SET */,
      packageName: this.packageName,
      sessionId: this.sessionId,
      requestId,
      fov,
      roiPosition,
      timestamp: new Date
    };
    this.session.sendMessage(message);
    this.logger.info({ fov, roiPosition, requestId }, "\uD83D\uDD2D Camera FOV set request sent");
  }
  async startLocalLivestream(options) {
    this.logger.info({ streamUrl: options.streamUrl }, `\uD83D\uDCF9 Stream request starting`);
    cameraWarnLog(this.session.getHttpsServerUrl?.(), this.packageName, "startLocalLivestream");
    if (!options.streamUrl) {
      throw new Error("streamUrl is required");
    }
    const url = options.streamUrl;
    if (!url.startsWith("rtmp://") && !url.startsWith("rtmps://") && !url.startsWith("srt://") && !url.startsWith("https://") && !url.startsWith("http://")) {
      throw new Error("Invalid stream URL: must start with rtmp://, rtmps://, srt://, https://, or http://");
    }
    if (this.isStreaming) {
      this.logger.error({
        currentStreamUrl: this.currentStreamUrl,
        requestedUrl: options.streamUrl
      }, `\uD83D\uDCF9 Already streaming error`);
      throw new Error("Already streaming. Stop the current stream before starting a new one.");
    }
    const message = {
      type: "stream_request" /* STREAM_REQUEST */,
      packageName: this.packageName,
      sessionId: this.sessionId,
      streamUrl: options.streamUrl,
      video: options.video,
      audio: options.audio,
      stream: options.stream,
      sound: options.sound,
      timestamp: new Date
    };
    this.currentStreamUrl = options.streamUrl;
    try {
      this.session.sendMessage(message);
      this.isStreaming = true;
      this.logger.info({ streamUrl: options.streamUrl }, `\uD83D\uDCF9 Stream request sent successfully`);
      return Promise.resolve();
    } catch (error) {
      this.logger.error({ error, streamUrl: options.streamUrl }, `\uD83D\uDCF9 Failed to send stream request`);
      const errorMessage = error instanceof Error ? error.message : String(error);
      return Promise.reject(`Failed to request stream: ${errorMessage}`);
    }
  }
  async stopLocalLivestream() {
    this.logger.info({
      isCurrentlyStreaming: this.isStreaming,
      currentStreamUrl: this.currentStreamUrl
    }, `\uD83D\uDCF9 Stream stop request`);
    if (!this.isStreaming) {
      this.logger.info(`\uD83D\uDCF9 Not streaming - no-op`);
      return Promise.resolve();
    }
    const message = {
      type: "stream_stop" /* STREAM_STOP */,
      packageName: this.packageName,
      sessionId: this.sessionId,
      streamId: this.currentStreamState?.streamId,
      timestamp: new Date
    };
    try {
      this.session.sendMessage(message);
      return Promise.resolve();
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      return Promise.reject(`Failed to stop RTMP stream: ${errorMessage}`);
    }
  }
  isCurrentlyStreaming() {
    return this.isStreaming;
  }
  getCurrentStreamUrl() {
    return this.currentStreamUrl;
  }
  getStreamStatus() {
    return this.currentStreamState;
  }
  subscribeToStreamStatusUpdates() {
    if (this.session) {
      this.session.subscribe("stream_status" /* STREAM_STATUS */);
    } else {
      this.logger.error("Cannot subscribe to status updates: session reference not available");
    }
  }
  unsubscribeFromStreamStatusUpdates() {
    if (this.session) {
      this.session.unsubscribe("stream_status" /* STREAM_STATUS */);
    }
  }
  onLocalLivestreamStatus(handler) {
    if (!this.session) {
      this.logger.error("Cannot listen for status updates: session reference not available");
      return () => {};
    }
    this.subscribeToStreamStatusUpdates();
    return this.session.on("stream_status" /* STREAM_STATUS */, handler);
  }
  updateStreamState(message) {
    this.logger.debug({
      messageType: message?.type,
      messageStatus: message?.status,
      currentIsStreaming: this.isStreaming
    }, `\uD83D\uDCF9 Stream state update`);
    if (!isStreamStatus(message)) {
      this.logger.warn({ message }, `\uD83D\uDCF9 Received invalid stream status message`);
      return;
    }
    const status = {
      type: message.type,
      streamId: message.streamId,
      status: message.status,
      errorDetails: message.errorDetails,
      appId: message.appId,
      stats: message.stats,
      timestamp: message.timestamp || new Date
    };
    this.logger.info({
      streamId: status.streamId,
      oldStatus: this.currentStreamState?.status,
      newStatus: status.status,
      wasStreaming: this.isStreaming
    }, `\uD83D\uDCF9 Stream status processed`);
    if (status.status === "stopped" || status.status === "error" || status.status === "timeout") {
      this.logger.info({
        status: status.status,
        wasStreaming: this.isStreaming
      }, `\uD83D\uDCF9 Stream stopped - updating local state`);
      this.isStreaming = false;
      this.currentStreamUrl = undefined;
    }
    this.currentStreamState = status;
  }
  async startLivestream(options) {
    return this.managedExtension.startManagedStream(options);
  }
  async stopLivestream() {
    return this.managedExtension.stopManagedStream();
  }
  onLivestreamStatus(handler) {
    return this.managedExtension.onManagedStreamStatus(handler);
  }
  isLivestreamActive() {
    return this.managedExtension.isManagedStreamActive();
  }
  getLivestreamUrls() {
    return this.managedExtension.getManagedStreamUrls();
  }
  async startManagedStream(options) {
    return this.startLivestream(options);
  }
  async stopManagedStream() {
    return this.stopLivestream();
  }
  onManagedStreamStatus(handler) {
    return this.onLivestreamStatus(handler);
  }
  isManagedStreamActive() {
    return this.isLivestreamActive();
  }
  getManagedStreamUrls() {
    return this.getLivestreamUrls();
  }
  async startStream(options) {
    return this.startLocalLivestream(options);
  }
  async stopStream() {
    return this.stopLocalLivestream();
  }
  onStreamStatus(handler) {
    return this.onLocalLivestreamStatus(handler);
  }
  async checkExistingStream() {
    return this.managedExtension.checkExistingStream();
  }
  handleStreamCheckResponse(response) {
    this.managedExtension.handleStreamCheckResponse(response);
  }
  handleManagedStreamStatus(message) {
    this.managedExtension.handleManagedStreamStatus(message);
  }
  updateSessionId(newSessionId) {
    this.sessionId = newSessionId;
  }
  cancelAllRequests() {
    const photoRequests = this.cancelAllPhotoRequests();
    if (this.isStreaming) {
      this.stopLocalLivestream().catch((error) => {
        this.logger.error({ error }, "Error stopping stream during cleanup");
      });
    }
    this.managedExtension.cleanup();
    return { photoRequests };
  }
}

