function generateRequestId3() {
  if (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") {
    return `photo_req_${crypto.randomUUID()}`;
  }
  return `photo_req_${Date.now()}_${Math.random().toString(36).substring(2, 11)}`;
}

